css:
.centered {
  position: fixed;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}

.email {
  animation-name: scaleAnimation;
  animation-duration: 5s;
  animation-fill-mode: both;
}

@keyframes scaleAnimation {
  0% {
    transform: scale(2);
  }
  100% {
    transform: scale(1);
  }
}
